"use client";

import React, { useRef } from "react";
import { useCoverflow } from "./useCoverflow";
import { CoverflowCard } from "./CoverflowCard";
import { cn } from "../../lib/utils";

const items = [
  {
    id: "1",
    image: "https://images.unsplash.com/photo-1509198397868-475647b2a1e5?q=80&w=600&auto=format&fit=crop",
    title: "Desert dunes"
  },
  {
    id: "2",
    image: "https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?q=80&w=600&auto=format&fit=crop",
    title: "Urban geometry"
  },
  {
    id: "3",
    image: "https://images.unsplash.com/photo-1518005020951-eccb494ad742?q=80&w=600&auto=format&fit=crop",
    title: "Minimalist steps"
  },
  {
    id: "4",
    image: "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?q=80&w=600&auto=format&fit=crop",
    title: "Mountain peaks"
  },
  {
    id: "5",
    image: "https://images.unsplash.com/photo-1502224562085-639556652f33?q=80&w=600&auto=format&fit=crop",
    title: "Architectural curve"
  },
  {
    id: "6",
    image: "https://images.unsplash.com/photo-1470071459604-3b5ec3a7fe05?q=80&w=600&auto=format&fit=crop",
    title: "Misty forest"
  }
];

export function CoverflowCarousel({ className }: { className?: string }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const loop = true;

  const {
    smoothIndex,
    targetIndex,
    xVal,
    isDragging,
    dragStartOffset,
    isHovered,
    next,
    prev,
    navigateTo,
  } = useCoverflow({
    totalItems: items.length,
    initialIndex: 2,
    autoPlay: true,
    interval: 4000,
    loop: true,
  });

  // Track position state for drag math
  const startXRef = useRef(0);
  const lastWheelSnapRef = useRef(0);

  // Keyboard navigation
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "ArrowLeft") {
      e.preventDefault();
      prev();
    } else if (e.key === "ArrowRight") {
      e.preventDefault();
      next();
    }
  };

  // Mouse Drag / Touch Gestures
  const handleDragStart = (clientX: number) => {
    isDragging.current = true;
    startXRef.current = clientX;
    dragStartOffset.current = xVal.get();
  };

  const handleDragMove = (clientX: number) => {
    if (!isDragging.current) return;
    const deltaX = clientX - startXRef.current;

    // Card width is 260px. Dragging by 260px shifts the index by 1.0.
    const sensitivity = 260;
    const nextOffset = dragStartOffset.current - deltaX / sensitivity;

    if (loop) {
      xVal.set(nextOffset);
    } else {
      // Add slight friction when dragging past ends in non-loop mode
      const clampedOffset = Math.max(0, Math.min(items.length - 1, nextOffset));
      xVal.set(clampedOffset);
    }
  };

  const handleDragEnd = () => {
    if (!isDragging.current) return;
    isDragging.current = false;

    // Find nearest snap target
    const rawVal = xVal.get();
    let snappedIndex = Math.round(rawVal);

    if (!loop) {
      snappedIndex = Math.max(0, Math.min(items.length - 1, snappedIndex));
    }

    targetIndex.current = snappedIndex;
    xVal.set(snappedIndex);
  };

  // Mouse Wheel / Trackpad navigation (with 350ms snaps cooldown)
  const handleWheel = (e: React.WheelEvent) => {
    const delta = e.deltaX || e.deltaY;
    if (Math.abs(delta) < 15) return;

    e.preventDefault();
    const now = Date.now();
    if (now - lastWheelSnapRef.current < 350) return;

    lastWheelSnapRef.current = now;
    const direction = Math.sign(delta);
    navigateTo(targetIndex.current + direction);
  };

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full h-[480px] overflow-hidden flex flex-col items-center justify-center select-none bg-[#050507] border border-neutral-900 rounded-3xl p-6 outline-none",
        className
      )}
      tabIndex={0}
      onKeyDown={handleKeyDown}
      onMouseEnter={() => {
        isHovered.current = true;
      }}
      onMouseLeave={() => {
        isHovered.current = false;
        handleDragEnd();
      }}
    >
      {/* 3D Viewport container */}
      <div
        className="relative w-full h-[400px] flex items-center justify-center cursor-grab active:cursor-grabbing"
        style={{
          perspective: "1200px",
          transformStyle: "preserve-3d",
        }}
        onMouseDown={(e) => handleDragStart(e.clientX)}
        onMouseMove={(e) => handleDragMove(e.clientX)}
        onMouseUp={handleDragEnd}
        onTouchStart={(e) => {
          if (e.touches[0]) handleDragStart(e.touches[0].clientX);
        }}
        onTouchMove={(e) => {
          if (e.touches[0]) handleDragMove(e.touches[0].clientX);
        }}
        onTouchEnd={handleDragEnd}
        onWheel={handleWheel}
      >
        {/* Track holding all items */}
        <div
          className="relative w-full h-full flex items-center justify-center"
          style={{ transformStyle: "preserve-3d" }}
        >
          {items.map((item, idx) => (
            <CoverflowCard
              key={item.id}
              item={item}
              index={idx}
              totalItems={items.length}
              smoothIndex={smoothIndex}
              loop={loop}
              onClick={() => {
                // If clicked, bring card to center
                if (!isDragging.current) {
                  navigateTo(idx);
                }
              }}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

"use client";

import { motion, useTransform, MotionValue } from "framer-motion";
import { CarouselItem } from "./types";
import { getCircularDistance, getCardTransforms } from "./utils";

interface CoverflowCardProps {
  item: CarouselItem;
  index: number;
  totalItems: number;
  smoothIndex: MotionValue<number>;
  loop: boolean;
  onClick: () => void;
}

function getImageUrl(image: any): string {
  if (!image) return "";
  if (typeof image === "string") return image;
  if (typeof image === "object") {
    if ("src" in image) return image.src;
    if ("default" in image) return image.default;
  }
  return "";
}

export function CoverflowCard({
  item,
  index,
  totalItems,
  smoothIndex,
  loop,
  onClick,
}: CoverflowCardProps) {
  // Track circular modular distance d relative to scroll position
  const d = useTransform(smoothIndex, (cVal) => {
    return getCircularDistance(index, cVal, totalItems, loop);
  });

  // Dynamically map positions from modular distance
  const rotateY = useTransform(d, (val) => getCardTransforms(val).rotateY);
  const x = useTransform(d, (val) => getCardTransforms(val).translateX);
  const z = useTransform(d, (val) => getCardTransforms(val).translateZ);
  const scale = useTransform(d, (val) => getCardTransforms(val).scale);
  const opacity = useTransform(d, (val) => getCardTransforms(val).opacity);
  const zIndex = useTransform(d, (val) => getCardTransforms(val).zIndex);
  const overlayOpacity = useTransform(d, (val) => getCardTransforms(val).overlayOpacity);

  return (
    <motion.div
      style={{
        rotateY,
        x,
        z,
        scale,
        opacity,
        zIndex,
        transformStyle: "preserve-3d",
      }}
      onClick={onClick}
      className="absolute top-0 left-1/2 -ml-[130px] w-[260px] h-[340px] rounded-2xl cursor-pointer select-none transform-gpu will-change-transform shadow-[0_16px_40px_rgba(0,0,0,0.8)] border border-white/5 bg-neutral-900 overflow-visible group"
      aria-label={`Slide ${index + 1}: ${item.title || "Image"}`}
      role="group"
    >
      <div className="relative w-full h-full rounded-2xl overflow-hidden pointer-events-none transform-gpu transition-transform duration-500 group-hover:scale-[1.02]">
        {/* Darkening overlay for background cards */}
        <motion.div
          style={{ opacity: overlayOpacity }}
          className="absolute inset-0 bg-black pointer-events-none z-10"
        />

        {/* Core Card Image */}
        <img
          src={getImageUrl(item.image)}
          alt={item.title || ""}
          className="w-full h-full object-cover select-none pointer-events-none grayscale"
          draggable={false}
        />

        {/* Text details overlay: centered flex badge with zero fractional transforms */}

      </div>

      {/* Cinematic Mirror Reflection - using mask-image with linear gradients */}
      <div 
        className="absolute top-[102%] left-0 right-0 h-[30%] overflow-hidden pointer-events-none select-none opacity-30 transform scaleY(-1) origin-top rounded-b-2xl border-t border-white/10"
        style={{
          WebkitMaskImage: "linear-gradient(to bottom, rgba(0,0,0,0.3) 0%, transparent 80%)",
          maskImage: "linear-gradient(to bottom, rgba(0,0,0,0.3) 0%, transparent 80%)",
        }}
      >
        <img
          src={getImageUrl(item.image)}
          alt=""
          className="w-full h-full object-cover grayscale"
          draggable={false}
        />
      </div>
    </motion.div>
  );
}

export type CarouselItem = {
  id: string;
  image: any;
  title?: string;
  subtitle?: string;
};

export interface CoverflowCarouselProps {
  items: CarouselItem[];
  initialIndex?: number;
  autoPlay?: boolean;
  interval?: number;
  loop?: boolean;
  className?: string;
}

/**
 * Helper to interpolate a value along a defined set of checkpoints
 */
export function interpolate(value: number, input: number[], output: number[]): number {
  if (value <= input[0]) return output[0];
  if (value >= input[input.length - 1]) return output[output.length - 1];
  for (let i = 0; i < input.length - 1; i++) {
    if (value >= input[i] && value <= input[i + 1]) {
      const ratio = (value - input[i]) / (input[i + 1] - input[i]);
      return output[i] + ratio * (output[i + 1] - output[i]);
    }
  }
  return output[0];
}

/**
 * Calculates the shortest modular distance between card index i and current scroll position C
 */
export function getCircularDistance(i: number, C: number, N: number, loop: boolean): number {
  const diff = i - C;
  if (!loop) return diff;
  const modDiff = ((diff % N) + N) % N;
  if (modDiff > N / 2) {
    return modDiff - N;
  }
  return modDiff;
}

export type CardTransformState = {
  rotateY: number;
  translateX: number;
  translateZ: number;
  scale: number;
  opacity: number;
  zIndex: number;
  overlayOpacity: number;
};

/**
 * Solves the exact 3D coordinates based on modular distance d
 */
export function getCardTransforms(d: number): CardTransformState {
  const absD = Math.abs(d);
  const sign = Math.sign(d);

  // Data point mappings matching the specification checklist exactly
  const dPoints = [0, 1, 2, 3, 4];
  const rotYPoints = [0, 45, 65, 75, 80];
  const scalePoints = [1.0, 0.9, 0.8, 0.7, 0.5];
  const transXPoints = [0, 140, 260, 380, 480];
  const transZPoints = [100, -50, -180, -320, -450];
  const opacityPoints = [1.0, 0.9, 0.6, 0.25, 0.0];
  const overlayOpacityPoints = [0.0, 0.35, 0.65, 0.85, 1.0];

  const rotateY = -sign * interpolate(absD, dPoints, rotYPoints);
  const scale = interpolate(absD, dPoints, scalePoints);
  const translateX = sign * interpolate(absD, dPoints, transXPoints);
  const translateZ = interpolate(absD, dPoints, transZPoints);
  const opacity = interpolate(absD, dPoints, opacityPoints);
  const overlayOpacity = interpolate(absD, dPoints, overlayOpacityPoints);

  // Z-index layout layering mapping
  const zIndex = Math.round(100 - absD * 10);

  return {
    rotateY,
    translateX,
    translateZ,
    scale,
    opacity,
    zIndex,
    overlayOpacity,
  };
}

"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import { useMotionValue, useSpring } from "framer-motion";
import { getCircularDistance } from "./utils";

export interface UseCoverflowProps {
  totalItems: number;
  initialIndex?: number;
  autoPlay?: boolean;
  interval?: number;
  loop?: boolean;
}

export function useCoverflow({
  totalItems,
  initialIndex = 0,
  autoPlay = false,
  interval = 4000,
  loop = true,
}: UseCoverflowProps) {
  // snapIndex tracks the actual integer target page index (0 to totalItems - 1)
  const [activeSnapIndex, setActiveSnapIndex] = useState(initialIndex);

  // targetIndex is a virtual index that grows infinitely to support smooth infinite loop scrolling
  const targetIndexRef = useRef(initialIndex);

  const xVal = useMotionValue(initialIndex);
  const smoothIndex = useSpring(xVal, {
    stiffness: 180,
    damping: 20,
    mass: 0.8,
  });

  const isDraggingRef = useRef(false);
  const dragStartOffsetRef = useRef(0);
  const autoplayTimerRef = useRef<NodeJS.Timeout | null>(null);
  const isHoveredRef = useRef(false);

  // Sync state index when smoothIndex updates to update active item titles/labels
  useEffect(() => {
    const unsubscribe = smoothIndex.on("change", (latest) => {
      // Map floating smooth scroll position to base [0, N-1] index range
      let mapped = Math.round(latest) % totalItems;
      if (mapped < 0) mapped += totalItems;
      setActiveSnapIndex(mapped);
    });
    return () => unsubscribe();
  }, [smoothIndex, totalItems]);

  // Navigate to specific absolute index
  const navigateTo = useCallback(
    (index: number) => {
      let nextTarget = index;
      if (loop) {
        // Calculate shortest path on a circle from current target index
        const currentTarget = targetIndexRef.current;
        const diff = getCircularDistance(index % totalItems, currentTarget % totalItems, totalItems, true);
        nextTarget = currentTarget + diff;
      } else {
        // Clamp to item boundaries
        nextTarget = Math.max(0, Math.min(totalItems - 1, nextTarget));
      }

      targetIndexRef.current = nextTarget;
      xVal.set(nextTarget);
    },
    [loop, totalItems, xVal]
  );

  const next = useCallback(() => {
    navigateTo(targetIndexRef.current + 1);
  }, [navigateTo]);

  const prev = useCallback(() => {
    navigateTo(targetIndexRef.current - 1);
  }, [navigateTo]);

  // Autoplay loop setup
  useEffect(() => {
    if (!autoPlay) return;

    const startAutoplay = () => {
      autoplayTimerRef.current = setInterval(() => {
        if (!isHoveredRef.current && !isDraggingRef.current) {
          next();
        }
      }, interval);
    };

    startAutoplay();

    return () => {
      if (autoplayTimerRef.current) {
        clearInterval(autoplayTimerRef.current);
      }
    };
  }, [autoPlay, interval, next]);

  return {
    smoothIndex,
    activeSnapIndex,
    targetIndex: targetIndexRef,
    xVal,
    isDragging: isDraggingRef,
    dragStartOffset: dragStartOffsetRef,
    isHovered: isHoveredRef,
    next,
    prev,
    navigateTo,
  };
}
